  "code": "def encode(message):
    """
    For a given string, perform case inversion on all letters and replace each vowel with the letter that is two steps forward in the English alphabet. Only letters are considered in the input.

    Examples:
    >>> encode('test')
    'TGST'
    >>> encode('This is a message')
    'tHKS KS C MGSSCGG'
    """
    vowels = {'a', 'e', 'i', 'o', 'u', 'A', 'E', 'I', 'O', 'U'}
    vowel_map = {'a': 'c', 'e': 'g', 'i': 'k', 'o': 'q', 'u': 'w', 'A': 'C', 'E': 'G', 'I': 'K', 'O': 'Q', 'U': 'W'}
    encoded_message = []

    for char in message:
        if char.isalpha():
            if char in vowels:
                encoded_char = vowel_map[char]
            else:
                encoded_char = char.swapcase()
            encoded_message.append(encoded_char)
        else:
            encoded_message.append(char)

    return ''.join(encoded_message)",
